            if (rateioCredito.CodigoTipoCalculoRateioOption.IsSet)
                writer.WriteNumber("codigoTipoCalculoRateio", rateioCredito.CodigoTipoCalculoRateioOption.Value!.Value);

            if (rateioCredito.NumeroCpfCnpjTitularOption.IsSet)
                writer.WriteString("numeroCpfCnpjTitular", rateioCredito.NumeroCpfCnpjTitular);

            if (rateioCredito.CodigoFinalidadeTedOption.IsSet)
                writer.WriteString("codigoFinalidadeTed", rateioCredito.CodigoFinalidadeTed);

            if (rateioCredito.CodigoTipoContaDestinoTedOption.IsSet)
                writer.WriteString("codigoTipoContaDestinoTed", rateioCredito.CodigoTipoContaDestinoTed);

            if (rateioCredito.QuantidadeDiasFloatOption.IsSet)
                writer.WriteNumber("quantidadeDiasFloat", rateioCredito.QuantidadeDiasFloatOption.Value!.Value);

            if (rateioCredito.DataFloatCreditoOption.IsSet)
                writer.WriteString("dataFloatCredito", rateioCredito.DataFloatCreditoOption.Value!.Value.ToString(DataFloatCreditoFormat));
        }
    }
}
